mapper.select:
SELECT a.ID, a.PAYMENT_TITLE, a.PAYMENT_AMOUNT, a.PAYEE_NAME, a.APPLICANT_ID, a.APPLICANT_NAME, a.PAYMENT_TYPE, b.INSTANCE_STATUS as APPROVAL_STATUS, case b.INSTANCE_STATUS when '1' then '审批中' when '2' then '审批通过' when '3' then '审批不通过' when '4' then '已办结' else '未发起' end as APPROVAL_STATUS_LABEL, b.CURRENT_NODE_NAME, b.APPROVER_NAMES, b.PROC_INST_ID, b.PROC_DEF_ID, a.APPLY_TIME, a.EXPECTED_PAYMENT_TIME FROM BPM_APPLICATION_EXAMPLE a LEFT JOIN ( SELECT * FROM ( SELECT t.*, ROW_NUMBER() OVER(PARTITION BY BUSINESS_DATA_ID ORDER BY START_TIME DESC) as rn FROM BPM_BUSINESS_INSTANCE t ) WHERE rn = 1 ) b ON a.id = b.BUSINESS_DATA_ID
AND a.PAYMENT_TITLE LIKE '%' || #{paymentTitle, jdbcType=VARCHAR} || '%'
AND a.PAYEE_NAME LIKE '%' || #{payeeName, jdbcType=VARCHAR} || '%'
AND a.APPLICANT_ID = #{applicantId, jdbcType=NUMERIC}
AND a.APPLICANT_NAME LIKE '%' || #{applicantName, jdbcType=VARCHAR} || '%'
AND b.INSTANCE_STATUS = #{approvalStatus, jdbcType=VARCHAR}
AND a.PAYMENT_TYPE = #{paymentType, jdbcType=VARCHAR}
ORDER BY APPLY_TIME DESC

SELECT

FROM BPM_APPLICATION_EXAMPLE
WHERE ID = #{id, jdbcType=NUMERIC}
